import React from "react";
import { BrowserRouter, Routes, Route } from "react-router-dom";
import "./GoCapiba.css";
import Nav from '../../Components/Navbar/Navbar'

function GoCapiba() {
    return (
        <BrowserRouter>
            <Routes>
                <Route path="/" element={<Nav />}>
                    <Route index element={<Map />} />
                </Route>
            </Routes>
        </BrowserRouter>
    )
}
